                    Text("Applied on \(formattedDate(promo.appliedDate))")
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
                Spacer()
                Text("\(promo.discount)%")
                    .font(.title)
                    .bold()
                    .foregroundColor(.green)
            }
        }
        .padding()
        .background(
            LinearGradient(
                gradient: Gradient(colors: [Color.green.opacity(0.2), Color.blue.opacity(0.2)]),
