    private var promoHistorySection: some View {
        VStack(alignment: .leading, spacing: 10) {
            Text("Promotion History")
                .font(.headline)
            
            if promoManager.promoHistory.isEmpty {
                Text("No promotions applied yet")
                    .foregroundColor(.secondary)
                    .italic()
                    .frame(maxWidth: .infinity, alignment: .center)
                    .padding()
            } else {
                ScrollView {
                    VStack(spacing: 8) {
                        ForEach(promoManager.promoHistory.prefix(5)) { promo in
                            PromoHistoryRow(promo: promo)
                        }
