class UserAccount: ObservableObject {
    @Published var username: String
    @Published var activeDiscount: Int
    @Published var totalSavings: Double
    
    init() {
        self.username = "user@example.com"
        self.activeDiscount = 0
        self.totalSavings = 0.0
        loadAccount()
    }
    
    func applyDiscount(_ discount: Int) {
        activeDiscount = discount
        saveAccount()
    }
    
    func removeDiscount() {
        activeDiscount = 0
        saveAccount()
    }
    
    func addSavings(_ amount: Double) {
        totalSavings += amount
        saveAccount()
    }
    
    private func saveAccount() {
        UserDefaults.standard.set(activeDiscount, forKey: "activeDiscount")
        UserDefaults.standard.set(totalSavings, forKey: "totalSavings")
    }
    
    private func loadAccount() {
        activeDiscount = UserDefaults.standard.integer(forKey: "activeDiscount")
        totalSavings = UserDefaults.standard.double(forKey: "totalSavings")
    }
}